#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <inttypes.h>
#include <string.h>
#include <stdbool.h>

typedef struct Node {
    int64_t key;
    int cnt;
    struct Node *next;
} Node;

#define MOD 1000003 // size of hash table (prime > 1e6)
static Node *table[MOD];

static uint32_t hash_int64(int64_t x) {
    uint64_t v = (uint64_t)(x ^ (x >> 33));
    return (uint32_t)(v % MOD);
}

static void add(int64_t x) {
    uint32_t h = hash_int64(x);
    Node *p = table[h];
    while (p) {
        if (p->key == x) { p->cnt++; return; }
        p = p->next;
    }
    Node *n = (Node*)malloc(sizeof(Node));
    n->key = x; n->cnt = 1; n->next = table[h];
    table[h] = n;
}

static int count_ge2() {
    int total = 0;
    for (uint32_t i = 0; i < MOD; ++i) {
        Node *p = table[i];
        while (p) {
            if (p->cnt >= 2) total++;
            p = p->next;
        }
    }
    return total;
}

static void clear_table() {
    for (uint32_t i = 0; i < MOD; ++i) {
        Node *p = table[i];
        while (p) {
            Node *tmp = p; p = p->next; free(tmp);
        }
        table[i] = NULL;
    }
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long answer = 0;
        clear_table();
        for (int i = 0; i < N; ++i) {
            int M; scanf("%d", &M);
            int pos = 0, neg = 0;
            for (int j = 0; j < M; ++j) {
                long long x; scanf("%lld", &x);
                if (x > 0) pos++; else neg++;
                add(llabs(x));
            }
            answer += (long long)pos * (long long)neg;
        }
        answer += count_ge2();
        printf("%lld\n", answer);
    }
    return 0;
}

